import { useEffect, useState, useRef, useCallback } from "react";
import { Routes, Route, useNavigate, useLocation } from "react-router-dom";
import { api, fileDownloadUrl } from "@/lib/api";
import { useAuth } from "@/context/AuthContext";
import { useWebSocket } from "@/lib/websocket";
import { WebRTCTransfer } from "@/lib/webrtc";
import Sidebar from "@/components/Sidebar";
import ChatPanel from "@/components/ChatPanel";
import StoriesPage from "@/pages/StoriesPage";
import ProfilePage from "@/pages/ProfilePage";
import FriendsPanel from "@/components/FriendsPanel";
import { toast } from "sonner";

export default function AppShell() {
  const { user, logout } = useAuth();
  const navigate = useNavigate();
  const location = useLocation();
  const [chats, setChats] = useState([]);
  const [friends, setFriends] = useState([]);
  const [peers, setPeers] = useState([]);
  const [activeChat, setActiveChat] = useState(null);
  const [messages, setMessages] = useState([]);
  const [stories, setStories] = useState([]);
  const [showFriends, setShowFriends] = useState(false);

  const webrtcRef = useRef(null);

  const handleWsEvent = useCallback(async (data) => {
    if (data.type === "message") {
      const msg = data.message;
      // Append to current chat if matches
      setMessages((prev) => {
        if (activeChat && msg.chat_id === activeChat.chat_id) {
          if (prev.find((m) => m.message_id === msg.message_id)) return prev;
          return [...prev, msg];
        }
        return prev;
      });
      // refresh chat list to surface new DMs
      if (msg.chat_id.startsWith("dm:")) loadChats();
    } else if (data.type === "signal") {
      // WebRTC signaling
      webrtcRef.current?.handleSignal(data, async ({ blob, meta, fromUserId, transferId }) => {
        // Save the incoming file as a downloadable in-memory blob
        const url = URL.createObjectURL(blob);
        toast.success(`Received ${meta?.name || "file"} via WebRTC`, {
          action: { label: "Download", onClick: () => {
            const a = document.createElement("a");
            a.href = url; a.download = meta?.name || "file";
            a.click();
          } },
          duration: 15000,
        });
      });
    } else if (data.type === "typing") {
      // Could show typing indicator
    }
  }, [activeChat]);

  const { connected, send } = useWebSocket(handleWsEvent);

  useEffect(() => {
    if (!webrtcRef.current) {
      webrtcRef.current = new WebRTCTransfer({ wsSend: send, selfId: user?.user_id });
    }
  }, [send, user]);

  const loadChats = useCallback(async () => {
    try {
      const res = await api.get("/chats");
      setChats(res.data);
    } catch {}
  }, []);

  const loadFriends = useCallback(async () => {
    try {
      const [f, p] = await Promise.all([api.get("/friends"), api.get("/network/peers")]);
      setFriends(f.data);
      setPeers(p.data);
    } catch {}
  }, []);

  const loadStories = useCallback(async () => {
    try {
      const res = await api.get("/stories");
      setStories(res.data);
    } catch {}
  }, []);

  useEffect(() => {
    loadChats();
    loadFriends();
    loadStories();
    // Default active chat = public channel
    setActiveChat({ chat_id: "public:home", type: "public", title: "Public Home Channel" });
  }, [loadChats, loadFriends, loadStories]);

  useEffect(() => {
    if (!activeChat) return;
    let cancel = false;
    api.get(`/chats/${activeChat.chat_id}/messages`).then((res) => {
      if (!cancel) setMessages(res.data);
    }).catch(() => {});
    return () => { cancel = true; };
  }, [activeChat]);

  const handleSelectChat = (chat) => {
    setActiveChat(chat);
    navigate("/app");
  };

  const handleStartDM = async (otherUserId) => {
    try {
      const res = await api.post(`/chats/dm/${otherUserId}`);
      setActiveChat(res.data);
      await loadChats();
      navigate("/app");
    } catch (e) {
      toast.error("Could not open chat");
    }
  };

  const handleSendMessage = async ({ content, file, preferWebRTC }) => {
    if (!activeChat) return;
    let file_id = null;
    let transfer_mode = "cloud";

    // For DMs, try WebRTC first if both on same network or in same home_group
    if (file && preferWebRTC && activeChat.type === "dm" && activeChat.other_user) {
      const otherId = activeChat.other_user.user_id;
      const samePeer = peers.find((p) => p.user_id === otherId);
      if (samePeer) {
        // Try WebRTC
        try {
          await new Promise((resolve, reject) => {
            webrtcRef.current.initiateSend({
              targetUserId: otherId,
              file,
              onProgress: () => {},
              onComplete: () => { transfer_mode = "webrtc"; resolve(); },
              onError: (err) => reject(err),
            });
            setTimeout(() => reject(new Error("webrtc-slow")), 12000);
          });
          // Also store in cloud as a record (so message survives sessions)
        } catch (e) {
          transfer_mode = "cloud";
        }
      }
    }

    if (file) {
      const fd = new FormData();
      fd.append("file", file);
      const up = await api.post("/upload", fd, { headers: { "Content-Type": "multipart/form-data" } });
      file_id = up.data.file_id;
    }

    await api.post(`/chats/${activeChat.chat_id}/messages`, {
      chat_id: activeChat.chat_id,
      content: content || "",
      file_id,
      transfer_mode,
    });
  };

  return (
    <div className="flex h-screen w-full bg-[#FDFBF7] overflow-hidden">
      <Sidebar
        user={user}
        chats={chats}
        peers={peers}
        friends={friends}
        stories={stories}
        activeChat={activeChat}
        onSelectChat={handleSelectChat}
        onStartDM={handleStartDM}
        onOpenStories={() => navigate("/app/stories")}
        onOpenProfile={() => navigate("/app/profile")}
        onOpenFriends={() => setShowFriends(true)}
        onLogout={async () => { await logout(); navigate("/"); }}
        connected={connected}
        currentPath={location.pathname}
      />
      <Routes>
        <Route path="/" element={
          <ChatPanel
            user={user}
            chat={activeChat}
            messages={messages}
            peers={peers}
            onSend={handleSendMessage}
            onTyping={() => activeChat?.chat_id?.startsWith("dm:") && send({ type: "typing", chat_id: activeChat.chat_id })}
          />
        } />
        <Route path="/stories" element={<StoriesPage stories={stories} onChange={loadStories} />} />
        <Route path="/profile" element={<ProfilePage friends={friends} peers={peers} onChange={loadFriends} />} />
      </Routes>
      {showFriends && (
        <FriendsPanel
          onClose={() => setShowFriends(false)}
          onChange={loadFriends}
          friends={friends}
          peers={peers}
        />
      )}
    </div>
  );
}
